import styled from 'styled-components'
import brandIcon from '../../img/LandingPage/brandLogo.svg'

const Brand = () => {
  return (
    <BrandContainer>
      <img src={brandIcon} alt="brandIcon" />
      <span> Adam Jałocha </span>
      <span> Web developer </span>
    </BrandContainer>
  )
}


const BrandContainer = styled.div`
  display: grid;
  grid-template: 1fr 1fr / auto 1fr;
  column-gap: 0.5em;
  align-items: center;
  padding-top: 2em;

  & img {
    grid-column: 1;
    grid-row: 1/3;
    height: 100%;
    width: auto;
    border-radius: 4px;
    /* box-shadow: 0px 0px 2px black; */
    filter: invert(0.9)
  }

  & span {
    font-weight: 400;
    font-size: 0.8em;
  }
`

export default Brand
